  public_id,
  category,
  name,
  manufacturer,
  price,
  status,
  attributes,
  created_at,
  updated_at
)
SELECT public_id::uuid,
       category,
       name,
       manufacturer,
       price,
       'ACTIVE',
       attributes,
       now(),
       now()
FROM seed_parts
ON CONFLICT (public_id) DO UPDATE SET
  category = EXCLUDED.category,
  name = EXCLUDED.name,
  manufacturer = EXCLUDED.manufacturer,
  price = EXCLUDED.price,
  status = 'ACTIVE',
  attributes = EXCLUDED.attributes,
  updated_at = now();

