), matched_parts AS (
  SELECT p.id AS part_id,
         s.search_query,
         s.title,
         s.image_url,
         s.supplier_name,
         s.offer_url,
         s.low_price,
         s.raw_payload
  FROM seed_offers s
  JOIN parts p ON p.public_id = s.public_id::uuid
  WHERE p.deleted_at IS NULL
), upserted_offers AS (
  INSERT INTO part_external_offers (
    part_id,
    source,
    search_query,
    title,
    image_url,
    supplier_name,
    offer_url,
    low_price,
    raw_payload,
    refreshed_at,
    created_at,
    updated_at
  )
  SELECT part_id,
         'NAVER_SHOPPING_SEARCH',
         search_query,
         title,
         image_url,
         supplier_name,
         offer_url,
         low_price,
         raw_payload,
         '2026-06-29T18:10:00Z',
         now(),
         now()
  FROM matched_parts
  ON CONFLICT (part_id, source) WHERE deleted_at IS NULL
  DO UPDATE SET
    search_query = EXCLUDED.search_query,
    title = EXCLUDED.title,
    image_url = EXCLUDED.image_url,
    supplier_name = EXCLUDED.supplier_name,
    offer_url = EXCLUDED.offer_url,
    low_price = EXCLUDED.low_price,
    raw_payload = EXCLUDED.raw_payload,
    refreshed_at = EXCLUDED.refreshed_at,
    updated_at = now()
  RETURNING part_id, low_price, raw_payload
)
INSERT INTO price_snapshots (
  part_id,
  price,
  source,
  collected_at,
  raw_payload
)
SELECT part_id,
       low_price,
       'NAVER_SHOPPING_SEARCH',
       '2026-06-29T18:10:00Z',
       raw_payload
FROM upserted_offers;

SELECT setval(pg_get_serial_sequence('parts', 'id'), (SELECT max(id) FROM parts));
SELECT setval(pg_get_serial_sequence('price_snapshots', 'id'), (SELECT max(id) FROM price_snapshots));
